import * as React from "react";

export interface PlanReviewStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
}

const FIELDS: ReadonlyArray<{ id: string; label: string; required: boolean; pii: boolean }> = [
	{ id: "review_notes", label: "Review Notes", required: true, pii: false },
	{ id: "code_sections", label: "Applicable Code Sections", required: false, pii: false },
	{ id: "review_outcome", label: "Review Outcome", required: true, pii: false },
];

/**
 * Minimal review step for the plan_review workflow. Hosts wrap this with
 * the project-wide auth/tenant context — keeping the component dumb so
 * generated code stays portable across Next.js and plain Vite apps.
 */
export function PlanReviewStep(props: PlanReviewStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);

	const fire = React.useCallback(
		async (event: string) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, {});
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	return (
		<section data-testid="plan_review-step" aria-labelledby="plan_review-step-title">
			<header>
				<h2 id="plan_review-step-title">Review Building Plans for Code Compliance</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<dl>
				{FIELDS.map((field) => (
					<React.Fragment key={field.id}>
						<dt>{field.label}{field.required ? " *" : ""}{field.pii ? " (PII)" : ""}</dt>
						<dd>—</dd>
					</React.Fragment>
				))}
			</dl>
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("submit")}>
					Submit
				</button>
				<button type="button" disabled={busy} onClick={() => fire("approve")}>
					Approve
				</button>
			</footer>
		</section>
	);
}
